(function(){const e=window.matchMedia("(prefers-reduced-motion: reduce)").matches;if(e)return;const t=document.querySelectorAll("[data-logo-carousel-track]:not([data-animated])");t.forEach(function(e){if(!e.scrollWidth)return;const t=Number(e.dataset.logoCarouselDuration||25e3);e.setAttribute("data-animated","true");const n=e.scrollWidth/2;e.animate([{transform:"translateX(0)"},{transform:"translateX(-"+n+"px)"}],{duration:t,iterations:1/0,easing:"linear"})})})()